test.custom_test:
$results = [];
$ql->Reconnect();
$ql->Query ( "DROP TABLE IF EXISTS uuid_sql_dynamic" );
$ql->Query ( "DROP TABLE IF EXISTS uuid_http_dynamic" );
$ql->Query ( "CREATE TABLE uuid_http_dynamic ( id uuid, title text, tag string )" );

$ql->Query ( "CREATE TABLE uuid_sql_dynamic ( id uuid, title text, tag string )" );
$ql->Query ( "INSERT INTO uuid_sql_dynamic ( title, tag ) VALUES ( 'auto sql one', 'sql-auto-one' ), ( 'auto sql two', 'sql-auto-two' )" );
$sqlIdsRes = $ql->Query ( "SELECT id FROM uuid_sql_dynamic ORDER BY tag ASC" );
$sqlIds = [];
foreach ( explode ( "\n", trim ( $sqlIdsRes ) ) as $line )
{
	$line = trim ( $line );
	if ( preg_match ( '/^[0-9a-f]{8}-[0-9a-f]{4}-8[0-9a-f]{3}-8[0-9a-f]{3}-000000000000$/', $line ) )
		$sqlIds[] = $line;
}
$results[] = "sql generated id count=" . count ( $sqlIds );
$results[] = "sql generated id shape=" . ( count ( $sqlIds )==2 ? "true" : "false" );
$results[] = "sql generated ids distinct=" . ( count ( $sqlIds )==2 && $sqlIds[0]!==$sqlIds[1] ? "true" : "false" );
$sqlSearchRes = count ( $sqlIds ) ? $ql->Query ( "SELECT tag FROM uuid_sql_dynamic WHERE id='" . $sqlIds[0] . "'" ) : "";
$results[] = "sql generated id searchable=" . ( strpos ( $sqlSearchRes, "sql-auto-one" )!==false ? "true" : "false" );

$res = HttpQueryPost ( "json/replace", "application/json", '{ "table": "uuid_http_dynamic", "doc": { "title": "auto replace", "tag": "json-auto-replace" } }', 0, false );
$body = json_decode ( $res["rows"], true );
$id = isset ( $body["id"] ) ? $body["id"] : "";

$results[] = "json replace auto http_code=" . $res["http_code"];
$results[] = "json replace auto result=" . ( $body["result"] ?? "missing" );
$results[] = "json replace auto created=" . ( !empty ( $body["created"] ) ? "true" : "false" );
$results[] = "json replace auto status=" . ( $body["status"] ?? "missing" );
$results[] = "json replace auto id_is_uuid=" . ( preg_match ( '/^[0-9a-f]{8}-[0-9a-f]{4}-8[0-9a-f]{3}-8[0-9a-f]{3}-000000000000$/', $id ) ? "true" : "false" );

$res2 = HttpQueryPost ( "json/insert", "application/json", '{ "table": "uuid_http_dynamic", "doc": { "title": "auto insert", "tag": "json-auto-insert" } }', 0, false );
$body2 = json_decode ( $res2["rows"], true );
$id2 = isset ( $body2["id"] ) ? $body2["id"] : "";
$results[] = "json insert auto id_is_uuid=" . ( preg_match ( '/^[0-9a-f]{8}-[0-9a-f]{4}-8[0-9a-f]{3}-8[0-9a-f]{3}-000000000000$/', $id2 ) ? "true" : "false" );
$results[] = "json generated ids distinct=" . ( $id!=="" && $id2!=="" && $id!==$id2 ? "true" : "false" );

$search = HttpQueryPost ( "json/search", "application/json", '{ "table": "uuid_http_dynamic", "query": { "equals": { "tag": "json-auto-replace" } }, "_source": ["id", "tag"], "limit": 1 }', 0, false );
$searchBody = json_decode ( $search["rows"], true );
$hit = $searchBody["hits"]["hits"][0] ?? [];
$results[] = "json replace auto searchable=" . ( ( $hit["_id"] ?? "" )===$id && ( $hit["_source"]["id"] ?? "" )===$id ? "true" : "false" );

$ql->Query ( "DROP TABLE IF EXISTS uuid_sql_dynamic" );
$ql->Query ( "DROP TABLE IF EXISTS uuid_http_dynamic" );

